    std::tuple<uintptr_t, uintptr_t, uintptr_t> rec::layout(mspan* s)
    {
        uintptr_t size;
        uintptr_t n;
        uintptr_t total;
        total = s->npages << _PageShift;
        size = s->elemsize;
        if(size > 0)
        {
            n = total / size;
        }
        return {size, n, total};
    }

