    // Adds a finalizer to the object p. Returns true if it succeeded.
    bool addfinalizer(gocpp::unsafe_pointer p, funcval* f, uintptr_t nret, _type* fint, ptrtype* ot)
    {
        lock(& mheap_.speciallock);
        auto s = (golang::runtime::specialfinalizer*)(rec::alloc(gocpp::recv(mheap_.specialfinalizeralloc)));
        unlock(& mheap_.speciallock);
        s->special.kind = _KindSpecialFinalizer;
        s->fn = f;
        s->nret = nret;
        s->fint = fint;
        s->ot = ot;
        if(addspecial(p, & s->special))
        {
            // This is responsible for maintaining the same
            // GC-related invariants as markrootSpans in any
            // situation where it's possible that markrootSpans
            // has already run but mark termination hasn't yet.
            if(gcphase != _GCoff)
            {
                auto [base, span, gocpp_id_3] = findObject(uintptr_t(p), 0, 0);
                auto mp = acquirem();
                auto gcw = & rec::ptr(gocpp::recv(mp->p))->gcw;
                // Mark everything reachable from the object
                // so it's retained for the finalizer.
                if(! rec::noscan(gocpp::recv(span->spanclass)))
                {
                    scanobject(base, gcw);
                }
                // Mark the finalizer itself, since the
                // special isn't part of the GC'd heap.
                scanblock(uintptr_t(gocpp::unsafe_pointer(& s->fn)), goarch::PtrSize, & oneptrmask[0], gcw, nullptr);
                releasem(mp);
            }
            return true;
        }

        // There was an old finalizer
        lock(& mheap_.speciallock);
        rec::free(gocpp::recv(mheap_.specialfinalizeralloc), gocpp::unsafe_pointer(s));
        unlock(& mheap_.speciallock);
        return false;
    }

    // Removes the finalizer (if any) from the object p.
    void removefinalizer(gocpp::unsafe_pointer p)
    {
        auto s = (golang::runtime::specialfinalizer*)(gocpp::unsafe_pointer(removespecial(p, _KindSpecialFinalizer)));
        if(s == nullptr)
        {
            // there wasn't a finalizer to remove
            return;
        }
        lock(& mheap_.speciallock);
        rec::free(gocpp::recv(mheap_.specialfinalizeralloc), gocpp::unsafe_pointer(s));
        unlock(& mheap_.speciallock);
    }

